import express from 'express';
import request from 'supertest';

jest.mock('@ims/auth', () => ({
  authenticate: (_req: any, _res: any, next: any) => next(),
  writeRoleGuard: (..._roles: string[]) => (_req: any, _res: any, next: any) => next(),
}));

jest.mock('@ims/monitoring', () => ({
  createLogger: () => ({ info: jest.fn(), error: jest.fn(), warn: jest.fn(), debug: jest.fn() }),
}));

jest.mock('@ims/instant-start', () => ({
  listPacks: jest.fn(),
  searchPacks: jest.fn(),
  listPacksByStandard: jest.fn(),
  getPack: jest.fn(),
  getManifest: jest.fn(),
  packExists: jest.fn(),
  validateCustomisation: jest.fn(),
  validatePrerequisites: jest.fn(),
  applyCustomisation: jest.fn(),
  installPack: jest.fn(),
}));

import instantStartRouter from '../src/routes/instant-start';
import {
  listPacks,
  searchPacks,
  listPacksByStandard,
  getManifest,
  validateCustomisation,
  validatePrerequisites,
  installPack,
} from '@ims/instant-start';

const mockListPacks = listPacks as jest.MockedFunction<typeof listPacks>;
const mockSearchPacks = searchPacks as jest.MockedFunction<typeof searchPacks>;
const mockListPacksByStandard = listPacksByStandard as jest.MockedFunction<typeof listPacksByStandard>;
const mockGetManifest = getManifest as jest.MockedFunction<typeof getManifest>;
const mockValidateCustomisation = validateCustomisation as jest.MockedFunction<typeof validateCustomisation>;
const mockValidatePrerequisites = validatePrerequisites as jest.MockedFunction<typeof validatePrerequisites>;
const mockInstallPack = installPack as jest.MockedFunction<typeof installPack>;

const app = express();
app.use(express.json());
app.use((req: any, _res: any, next: any) => {
  req.user = { id: 'user-1', organisationId: 'org-1', email: 'admin@example.com' };
  next();
});
app.use('/api/instant-start', instantStartRouter);

function makeManifest(id: string) {
  return {
    id,
    name: `Pack ${id}`,
    description: `Description for ${id}`,
    version: '1.0.0',
    standards: ['ISO 9001'],
    industry: 'general',
    customisationOptions: [
      { key: 'companyName', type: 'string', label: 'Company Name', required: true },
      { key: 'employeeCount', type: 'number', label: 'Employee Count', required: false },
      { key: 'enableAI', type: 'boolean', label: 'Enable AI', required: false, default: true },
    ],
    prerequisites: ['quality', 'documents'],
  };
}

const PACK_IDS = [
  'automotive-iatf-16949',
  'construction-iso45001',
  'medtech-iso13485',
  'food-safety-brcgs',
  'professional-services-iso27001',
];

function makeInstallResult(packId: string) {
  return {
    success: true,
    packId,
    organisationId: 'org-1',
    installedAt: new Date().toISOString(),
    itemsCreated: { documents: 10, risks: 5, templates: 3 },
  };
}

beforeEach(() => {
  jest.clearAllMocks();
  mockListPacks.mockReturnValue(PACK_IDS.map(makeManifest) as any);
  mockSearchPacks.mockReturnValue([makeManifest('automotive-iatf-16949')] as any);
  mockListPacksByStandard.mockReturnValue([makeManifest('construction-iso45001')] as any);
  mockGetManifest.mockReturnValue(makeManifest('automotive-iatf-16949') as any);
  mockValidateCustomisation.mockReturnValue({ valid: true, errors: [], warnings: [] });
  mockValidatePrerequisites.mockReturnValue({ valid: true, errors: [], warnings: [] });
  mockInstallPack.mockResolvedValue(makeInstallResult('automotive-iatf-16949') as any);
});

